"use client";

import { useState, useEffect } from "react";
import Image from "next/image";

interface Comment {
    id: number;
    message: string;
    author: string;
    timestamp: string;
    avatar?: string;
}

export default function FanComments() {
    const [comments, setComments] = useState<Comment[]>([]);
    const [currentCommentIndex, setCurrentCommentIndex] = useState(0);

    // 더미 데이터
    const dummyComments: Comment[] = [
        {
            id: 1,
            message: "이채영 언니 사랑해요! 항상 응원할게요 💕",
            author: "fromis9_fan_01",
            timestamp: "2분 전",
            avatar: "/hero/11.png"
        },
        {
            id: 2,
            message: "새 앨범 너무 기대돼요! 언제 나와요?",
            author: "music_lover_99",
            timestamp: "5분 전",
            avatar: "/hero/21.png"
        },
        {
            id: 3,
            message: "무대에서 빛나는 모습이 정말 아름다워요 ✨",
            author: "stage_queen",
            timestamp: "8분 전",
            avatar: "/hero/31.png"
        },
        {
            id: 4,
            message: "힘든 일이 있어도 팬들이 있어요! 화이팅!",
            author: "support_team",
            timestamp: "12분 전",
            avatar: "/hero/41.png"
        },
        {
            id: 5,
            message: "오늘도 수고하셨어요. 좋은 꿈 꾸세요 🌙",
            author: "night_owl",
            timestamp: "15분 전",
            avatar: "/hero/51.png"
        },
        {
            id: 6,
            message: "fromis9와 함께한 시간이 가장 행복해요",
            author: "happy_fan",
            timestamp: "20분 전",
            avatar: "/hero/12.png"
        },
        {
            id: 7,
            message: "언니 목소리 듣고 있으면 마음이 따뜻해져요",
            author: "warm_heart",
            timestamp: "25분 전",
            avatar: "/hero/22.png"
        },
        {
            id: 8,
            message: "다음 콘서트에서 만나요! 기대돼요 🎵",
            author: "concert_goer",
            timestamp: "30분 전",
            avatar: "/hero/32.png"
        }
    ];

    // 댓글 애니메이션 효과
    useEffect(() => {
        const interval = setInterval(() => {
            setCurrentCommentIndex((prev) => (prev + 1) % dummyComments.length);
        }, 3000); // 3초마다 댓글 변경

        return () => clearInterval(interval);
    }, []);

    // 댓글 추가 효과
    useEffect(() => {
        if (currentCommentIndex < dummyComments.length) {
            const timer = setTimeout(() => {
                setComments(prev => [...prev, dummyComments[currentCommentIndex]]);
            }, 500);
            return () => clearTimeout(timer);
        }
    }, [currentCommentIndex]);

    return (
        <div className="min-h-screen bg-gradient-to-br from-pink-50 via-purple-50 to-blue-50 relative overflow-hidden">
            {/* 배경 이미지들 */}
            <div className="absolute inset-0 opacity-20">
                <div className="absolute top-10 left-10 w-32 h-32 rounded-full bg-pink-200 animate-pulse"></div>
                <div className="absolute top-1/4 right-20 w-24 h-24 rounded-full bg-purple-200 animate-bounce"></div>
                <div className="absolute bottom-1/4 left-1/4 w-20 h-20 rounded-full bg-blue-200 animate-ping"></div>
                <div className="absolute bottom-20 right-1/3 w-28 h-28 rounded-full bg-yellow-200 animate-pulse"></div>
            </div>

            {/* 메인 컨텐츠 */}
            <div className="relative z-10 p-8">
                {/* 헤더 */}
                <div className="text-center mb-12">
                    <h1 className="text-4xl font-bold text-gray-800 mb-4">
                        💌 팬들의 마음 💌
                    </h1>
                    <p className="text-lg text-gray-600">
                        fromis9에게 전하는 사랑의 메시지
                    </p>
                </div>

                {/* 아티스트 이미지 */}
                <div className="flex justify-center mb-12">
                    <div className="relative">
                        <div className="w-48 h-48 rounded-full overflow-hidden shadow-2xl animate-pulse">
                            <Image
                                src="/hero/52.png"
                                alt="fromis9"
                                width={192}
                                height={192}
                                className="w-full h-full object-cover"
                            />
                        </div>
                        <div className="absolute -top-2 -right-2 w-8 h-8 bg-red-500 rounded-full flex items-center justify-center animate-bounce">
                            <span className="text-white text-sm">💕</span>
                        </div>
                    </div>
                </div>

                {/* 댓글 컨테이너 */}
                <div className="max-w-4xl mx-auto">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {comments.map((comment, index) => (
                            <div
                                key={comment.id}
                                className={`bg-white rounded-2xl p-6 shadow-lg transform transition-all duration-1000 ${index === comments.length - 1
                                    ? 'animate-slideInUp scale-105'
                                    : 'hover:scale-105 hover:shadow-xl'
                                    }`}
                                style={{
                                    animationDelay: `${index * 0.2}s`,
                                    animationFillMode: 'both'
                                }}
                            >
                                {/* 아바타와 작성자 */}
                                <div className="flex items-center mb-4">
                                    <div className="w-12 h-12 rounded-full overflow-hidden mr-3">
                                        <Image
                                            src={comment.avatar || "/hero/11.png"}
                                            alt={comment.author}
                                            width={48}
                                            height={48}
                                            className="w-full h-full object-cover"
                                        />
                                    </div>
                                    <div>
                                        <p className="font-semibold text-gray-800">{comment.author}</p>
                                        <p className="text-sm text-gray-500">{comment.timestamp}</p>
                                    </div>
                                </div>

                                {/* 메시지 */}
                                <p className="text-gray-700 leading-relaxed">
                                    {comment.message}
                                </p>

                                {/* 하트 애니메이션 */}
                                <div className="flex justify-end mt-4">
                                    <span className="text-2xl animate-bounce">💖</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* 하단 메시지 */}
                <div className="text-center mt-16">
                    <p className="text-xl text-gray-600 mb-4">
                        계속해서 사랑의 메시지가 전달되고 있어요...
                    </p>
                    <div className="flex justify-center space-x-2">
                        <div className="w-3 h-3 bg-pink-400 rounded-full animate-bounce"></div>
                        <div className="w-3 h-3 bg-purple-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-3 h-3 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                    </div>
                </div>
            </div>

            {/* 커스텀 CSS 애니메이션 */}
            <style jsx>{`
                @keyframes slideInUp {
                    from {
                        opacity: 0;
                        transform: translateY(30px) scale(0.9);
                    }
                    to {
                        opacity: 1;
                        transform: translateY(0) scale(1);
                    }
                }
                .animate-slideInUp {
                    animation: slideInUp 0.8s ease-out;
                }
            `}</style>
        </div>
    );
}
